/*! igtc-language-role-bridge.min.js (cleaned) */
(function(){
  'use strict';
  var LANG_ALIAS={'ko-kr':'ko','en-us':'en','zh-cn':'zh'};
  window.normalizeLang=function(code){
    if(!code) return 'en';
    code=code.toLowerCase();
    if(LANG_ALIAS[code]) return LANG_ALIAS[code];
    if(code.includes('-')) return code.split('-')[0];
    return code;
  };
  window.getUserRole=function(){
    try { return localStorage.getItem('user_role')||'guest'; }
    catch(_){ return 'guest'; }
  };
})();